import os
import json
import hashlib
from pathlib import Path
from typing import Optional

import numpy as np
from openai import OpenAI

# --- Configuration ---
OPENAI_API_KEY = os.environ.get("OPENAI_API_KEY", "your-api-key-here")
EMBEDDING_MODEL = "text-embedding-3-small"
CHAT_MODEL = "gpt-4o-mini"
VECTOR_DB_PATH = "vector_store.json"
DOCUMENTS_DIR = "company_documents"
CHUNK_SIZE = 500
CHUNK_OVERLAP = 100
TOP_K = 5


# --- Vector Store ---
class SimpleVectorStore:
    """A simple file-backed vector store using cosine similarity."""

    def __init__(self, db_path: str = VECTOR_DB_PATH):
        self.db_path = db_path
        self.documents: list[dict] = []
        self.embeddings: list[list[float]] = []
        self._load()

    def _load(self):
        if os.path.exists(self.db_path):
            with open(self.db_path, "r", encoding="utf-8") as f:
                data = json.load(f)
                self.documents = data.get("documents", [])
                self.embeddings = data.get("embeddings", [])
            print(f"Loaded {len(self.documents)} documents from vector store.")
        else:
            print("No existing vector store found. Starting fresh.")

    def _save(self):
        with open(self.db_path, "w", encoding="utf-8") as f:
            json.dump({
                "documents": self.documents,
                "embeddings": self.embeddings
            }, f)
        print(f"Saved {len(self.documents)} documents to vector store.")

    def add_documents(self, documents: list[dict], embeddings: list[list[float]]):
        self.documents.extend(documents)
        self.embeddings.extend(embeddings)
        self._save()

    def search(self, query_embedding: list[float], top_k: int = TOP_K) -> list[dict]:
        if not self.embeddings:
            return []

        query_vec = np.array(query_embedding)
        doc_vecs = np.array(self.embeddings)

        # Cosine similarity
        query_norm = query_vec / (np.linalg.norm(query_vec) + 1e-10)
        doc_norms = doc_vecs / (np.linalg.norm(doc_vecs, axis=1, keepdims=True) + 1e-10)
        similarities = np.dot(doc_norms, query_norm)

        top_indices = np.argsort(similarities)[::-1][:top_k]

        results = []
        for idx in top_indices:
            results.append({
                "document": self.documents[idx],
                "score": float(similarities[idx])
            })
        return results

    def clear(self):
        self.documents = []
        self.embeddings = []
        if os.path.exists(self.db_path):
            os.remove(self.db_path)
        print("Vector store cleared.")

    def get_document_hashes(self) -> set[str]:
        return {doc.get("content_hash", "") for doc in self.documents}


# --- Document Processing ---
class DocumentProcessor:
    """Handles loading, chunking, and hashing of documents."""

    SUPPORTED_EXTENSIONS = {".txt", ".md", ".csv", ".json", ".py", ".html", ".log"}

    @staticmethod
    def compute_hash(text: str) -> str:
        return hashlib.sha256(text.encode("utf-8")).hexdigest()

    @staticmethod
    def chunk_text(text: str, chunk_size: int = CHUNK_SIZE, overlap: int = CHUNK_OVERLAP) -> list[str]:
        """Split text into overlapping chunks by word count."""
        words = text.split()
        chunks = []
        start = 0
        while start < len(words):
            end = start + chunk_size
            chunk = " ".join(words[start:end])
            if chunk.strip():
                chunks.append(chunk.strip())
            start += chunk_size - overlap
        return chunks if chunks else [text.strip()] if text.strip() else []

    @classmethod
    def load_file(cls, file_path: str) -> Optional[str]:
        path = Path(file_path)
        if path.suffix.lower() not in cls.SUPPORTED_EXTENSIONS:
            print(f"  Skipping unsupported file type: {path.name}")
            return None
        try:
            with open(path, "r", encoding="utf-8", errors="ignore") as f:
                content = f.read()
            return content if content.strip() else None
        except Exception as e:
            print(f"  Error reading {path.name}: {e}")
            return None

    @classmethod
    def load_directory(cls, directory: str) -> list[dict]:
        """Load all supported files from a directory and return document chunks with metadata."""
        dir_path = Path(directory)
        if not dir_path.exists():
            print(f"Directory '{directory}' does not exist.")
            return []

        all_chunks = []
        files = sorted(dir_path.rglob("*"))

        for file_path in files:
            if file_path.is_file():
                content = cls.load_file(str(file_path))
                if content:
                    chunks = cls.chunk_text(content)
                    for i, chunk in enumerate(chunks):
                        all_chunks.append({
                            "text": chunk,
                            "content_hash": cls.compute_hash(chunk),
                            "metadata": {
                                "source": str(file_path.relative_to(dir_path)),
                                "chunk_index": i,
                                "total_chunks": len(chunks),
                                "file_name": file_path.name,
                            }
                        })
                    print(f"  Loaded {file_path.name}: {len(chunks)} chunks")

        print(f"Total chunks from directory: {len(all_chunks)}")
        return all_chunks


# --- Embedding Service ---
class EmbeddingService:
    """Handles embedding generation via OpenAI API."""

    def __init__(self, client: OpenAI, model: str = EMBEDDING_MODEL):
        self.client = client
        self.model = model

    def embed_texts(self, texts: list[str], batch_size: int = 100) -> list[list[float]]:
        all_embeddings = []
        for i in range(0, len(texts), batch_size):
            batch = texts[i:i + batch_size]
            response = self.client.embeddings.create(
                model=self.model,
                input=batch
            )
            batch_embeddings = [item.embedding for item in response.data]
            all_embeddings.extend(batch_embeddings)
            print(f"  Embedded batch {i // batch_size + 1} ({len(batch)} texts)")
        return all_embeddings

    def embed_query(self, query: str) -> list[float]:
        response = self.client.embeddings.create(
            model=self.model,
            input=[query]
        )
        return response.data[0].embedding


# --- RAG Chatbot ---
class RAGChatbot:
    """Main RAG chatbot that orchestrates retrieval and generation."""

    SYSTEM_PROMPT = """You are a helpful internal knowledge base assistant for our company. 
Your role is to answer employee questions using the provided context from company documents.

Guidelines:
- Base your answers ONLY on the provided context documents.
- If the context doesn't contain enough information to answer the question, say so clearly.
- Cite the source document when possible (e.g., "According to [filename]...").
- Be concise but thorough.
- If multiple documents provide relevant information, synthesize them into a coherent answer.
- Do not make up information that isn't in the provided context."""

    def __init__(self):
        self.client = OpenAI(api_key=OPENAI_API_KEY)
        self.vector_store = SimpleVectorStore()
        self.embedding_service = EmbeddingService(self.client)
        self.processor = DocumentProcessor()
        self.conversation_history: list[dict] = []

    def ingest_documents(self, directory: str = DOCUMENTS_DIR, force_reload: bool = False):
        """Load documents from directory, embed them, and store in vector DB."""
        if force_reload:
            self.vector_store.clear()

        print(f"\n{'='*60}")
        print(f"Ingesting documents from: {directory}")
        print(f"{'='*60}")

        chunks = self.processor.load_directory(directory)
        if not chunks:
            print("No documents found to ingest.")
            return

        # Filter out already-indexed chunks
        existing_hashes = self.vector_store.get_document_hashes()
        new_chunks = [c for c in chunks if c["content_hash"] not in existing_hashes]

        if not new_chunks:
            print("All documents are already indexed. No new chunks to add.")
            return

        print(f"\nNew chunks to embed: {len(new_chunks)} (skipped {len(chunks) - len(new_chunks)} existing)")

        # Generate embeddings
        texts = [chunk["text"] for chunk in new_chunks]
        print("\nGenerating embeddings...")
        embeddings = self.embedding_service.embed_texts(texts)

        # Store in vector DB
        documents = []
        for chunk in new_chunks:
            documents.append({
                "content": chunk["text"],
                "content_hash": chunk["content_hash"],
                "source": chunk["metadata"]["source"],
                "file_name": chunk["metadata"]["file_name"],
                "chunk_index": chunk["metadata"]["chunk_index"],
                "total_chunks": chunk["metadata"]["total_chunks"],
            })

        self.vector_store.add_documents(documents, embeddings)
        print(f"\nIngestion complete! Total documents in store: {len(self.vector_store.documents)}")

    def retrieve(self, query: str, top_k: int = TOP_K) -> list[dict]:
        """Retrieve the most relevant document chunks for a query."""
        query_embedding = self.embedding_service.embed_query(query)
        results = self.vector_store.search(query_embedding, top_k=top_k)
        return results

    def _build_context_block(self, retrieved_docs: list[dict]) -> str:
        """Format retrieved documents into a context block for the LLM prompt."""
        if not retrieved_docs:
            return "No relevant documents were found in the knowledge base."

        context_parts = []
        for i, result in enumerate(retrieved_docs, 1):
            doc = result["document"]
            score = result["score"]
            source = doc.get("source", "Unknown")
            chunk_idx = doc.get("chunk_index", "?")
            total_chunks = doc.get("total_chunks", "?")
            content = doc.get("content", "")

            context_parts.append(
                f"--- Document {i} ---\n"
                f"Source: {source} (chunk {chunk_idx + 1}/{total_chunks})\n"
                f"Relevance Score: {score:.4f}\n"
                f"Content:\n{content}\n"
            )

        return "\n".join(context_parts)

    def _build_user_prompt(self, query: str, context_block: str) -> str:
        """Build the full user prompt including context and query."""
        return (
            f"RETRIEVED CONTEXT DOCUMENTS:\n"
            f"{'='*40}\n"
            f"{context_block}\n"
            f"{'='*40}\n\n"
            f"USER QUESTION: {query}\n\n"
            f"Please answer the question based on the context documents above."
        )

    def generate_response(self, query: str, retrieved_docs: list[dict]) -> str:
        """Generate a response using the LLM with retrieved context."""
        context_block = self._build_context_block(retrieved_docs)
        user_prompt = self._build_user_prompt(query, context_block)

        messages = [
            {"role": "system", "content": self.SYSTEM_PROMPT},
        ]

        # Include conversation history for multi-turn context
        for turn in self.conversation_history[-6:]:  # Last 3 exchanges
            messages.append(turn)

        messages.append({"role": "user", "content": user_prompt})

        response = self.client.chat.completions.create(
            model=CHAT_MODEL,
            messages=messages,
            temperature=0.2,
            max_tokens=1500,
        )

        assistant_message = response.choices[0].message.content

        # Store in conversation history
        self.conversation_history.append({"role": "user", "content": query})
        self.conversation_history.append({"role": "assistant", "content": assistant_message})

        return assistant_message

    def query(self, user_query: str, top_k: int = TOP_K, verbose: bool = False) -> str:
        """Full RAG pipeline: retrieve relevant docs and generate response."""
        print(f"\n{'─'*60}")
        print(f"Query: {user_query}")
        print(f"{'─'*60}")

        # Step 1: Retrieve
        print("Retrieving relevant documents...")
        retrieved_docs = self.retrieve(user_query, top_k=top_k)

        if verbose:
            print(f"\nRetrieved {len(retrieved_docs)} documents:")
            for i, result in enumerate(retrieved_docs, 1):
                doc = result["document"]
                print(f"  {i}. [{result['score']:.4f}] {doc['source']} "
                      f"(chunk {doc['chunk_index'] + 1}/{doc['total_chunks']})")

        # Step 2: Generate
        print("Generating response...")
        response = self.generate_response(user_query, retrieved_docs)

        print(f"\nAnswer:\n{response}")
        return response

    def reset_conversation(self):
        """Clear conversation history for a fresh start."""
        self.conversation_history.clear()
        print("Conversation history cleared.")

    def interactive_chat(self):
        """Run an interactive chat loop in the terminal."""
        print(f"\n{'='*60}")
        print("  Internal Knowledge Base Chatbot")
        print(f"{'='*60}")
        print("Commands:")
        print("  /quit      - Exit the chatbot")
        print("  /reset     - Clear conversation history")
        print("  /ingest    - Re-ingest documents")
        print("  /reload    - Force reload all documents")
        print("  /verbose   - Toggle verbose mode")
        print("  /status    - Show system status")
        print(f"{'='*60}\n")

        verbose = False

        while True:
            try:
                user_input = input("\nYou: ").strip()
            except (KeyboardInterrupt, EOFError):
                print("\nGoodbye!")
                break

            if not user_input:
                continue

            if user_input.lower() == "/quit":
                print("Goodbye!")
                break
            elif user_input.lower() == "/reset":
                self.reset_conversation()
                continue
            elif user_input.lower() == "/ingest":
                self.ingest_documents()
                continue
            elif user_input.lower() == "/reload":
                self.ingest_documents(force_reload=True)
                continue
            elif user_input.lower() == "/verbose":
                verbose = not verbose
                print(f"Verbose mode: {'ON' if verbose else 'OFF'}")
                continue
            elif user_input.lower() == "/status":
                print(f"Documents in store: {len(self.vector_store.documents)}")
                print(f"Conversation turns: {len(self.conversation_history) // 2}")
                print(f"Verbose: {'ON' if verbose else 'OFF'}")
                # Show unique source files
                sources = set(doc.get("source", "?") for doc in self.vector_store.documents)
                print(f"Indexed files ({len(sources)}):")
                for src in sorted(sources):
                    print(f"  - {src}")
                continue

            self.query(user_input, verbose=verbose)


