# --- Main Entry Point ---
def main():
    import sys

    if len(sys.argv) > 1:
        command = sys.argv[1].lower()
        if command == "create-samples":
            create_sample_documents()
            return
        elif command == "ingest":
            directory = sys.argv[2] if len(sys.argv) > 2 else DOCUMENTS_DIR
            chatbot = RAGChatbot()
            chatbot.ingest_documents(directory)
            return
        elif command == "query":
            if len(sys.argv) < 3:
                print("Usage: python rag_chatbot.py query 'your question here'")
                return
            question = " ".join(sys.argv[2:])
            chatbot = RAGChatbot()
            chatbot.query(question, verbose=True)
            return
        elif command == "help":
            print("Usage:")
            print("  python rag_chatbot.py                    - Start interactive chat")
            print("  python rag_chatbot.py create-samples     - Create sample documents")
            print("  python rag_chatbot.py ingest [dir]       - Ingest documents from directory")
            print("  python rag_chatbot.py query 'question'   - Ask a single question")
            print("  python rag_chatbot.py help               - Show this help message")
            return

    # Default: create samples if needed, ingest, and start interactive chat
    if not Path(DOCUMENTS_DIR).exists() or not any(Path(DOCUMENTS_DIR).iterdir()):
        print("No documents found. Creating sample documents for demo...")
        create_sample_documents()

    chatbot = RAGChatbot()
    chatbot.ingest_documents()
    chatbot.interactive_chat()


if __name__ == "__main__":
    main()